// Process all merged items from 3 platforms
const allItems = $input.all();
const results = [];
const debug = { total: allItems.length, skipped_empty: 0, skipped_no_platform: 0, skipped_filter: 0, accepted: 0, sample_keys: [] };

for (const item of allItems) {
  const d = item.json;
  if (!d || d._empty) { debug.skipped_empty++; continue; }

  // Log first item's keys for debugging
  if (debug.sample_keys.length === 0) debug.sample_keys = Object.keys(d).slice(0, 15);

  // Skip if already processed
  if (d.platform) { results.push(d); continue; }

  let platform = 'twitter';
  let id, prompt, author, authorName, likes, views, date, images = [], sourceUrl;

  // Twitter format
  if (d.full_text || d.text || d.id_str || d.tweetId) {
    platform = 'twitter';
    id = String(d.id || d.id_str || d.tweetId || '');
    const text = d.full_text || d.text || d.tweet || d.description || '';
    author = d.user?.screen_name || d.author?.userName || d.authorName || '';
    authorName = d.user?.name || d.author?.name || d.authorName || author;
    likes = d.favorite_count || d.likeCount || d.likes || 0;
    views = d.views_count || d.viewCount || d.views || 0;
    date = d.created_at ? new Date(d.created_at).toISOString().split('T')[0] : new Date().toISOString().split('T')[0];

    if (d.entities?.media) d.entities.media.forEach(m => { if (m.media_url_https) images.push(m.media_url_https); });
    if (d.extended_entities?.media) d.extended_entities.media.forEach(m => { if (m.media_url_https && !images.includes(m.media_url_https)) images.push(m.media_url_https); });
    if (d.media?.photos) d.media.photos.forEach(p => { if (p.url && !images.includes(p.url)) images.push(p.url); });
    if (d.mediaUrls) d.mediaUrls.forEach(url => { if (!images.includes(url)) images.push(url); });
    if (d.media_url && !images.includes(d.media_url)) images.push(d.media_url);

    prompt = text.replace(/https?:\/\/\S+/g, '').replace(/\n{3,}/g, '\n\n').replace(/(\n\s*#\w+\s*)+$/g, '').trim();
    sourceUrl = d.url || `https://x.com/${author}/status/${id}`;
  }
  // Threads format
  else if (d.username || (d.user && d.text)) {
    platform = 'threads';
    id = String(d.id || d.pk || '');
    const text = d.text || d.caption || '';
    author = d.username || d.user?.username || '';
    authorName = d.user?.full_name || author;
    likes = d.like_count || d.likeCount || d.likes || 0;
    views = d.view_count || 0;
    date = d.taken_at ? new Date(d.taken_at * 1000).toISOString().split('T')[0] : new Date().toISOString().split('T')[0];

    if (d.image_urls) images.push(...d.image_urls);
    if (d.carousel_media) d.carousel_media.forEach(m => { if (m.image_url) images.push(m.image_url); });
    if (d.displayUrl) images.push(d.displayUrl);
    if (d.image_versions2?.candidates?.[0]?.url) images.push(d.image_versions2.candidates[0].url);

    prompt = text.replace(/https?:\/\/\S+/g, '').trim();
    sourceUrl = d.url || `https://www.threads.net/@${author}/post/${id}`;
  }
  // Instagram format
  else if (d.ownerUsername || d.shortCode || d.displayUrl) {
    platform = 'instagram';
    id = String(d.id || d.shortCode || '');
    const text = d.caption || d.alt || '';
    author = d.ownerUsername || d.owner?.username || '';
    authorName = d.ownerFullName || author;
    likes = d.likesCount || d.like_count || 0;
    views = d.videoViewCount || 0;
    date = d.timestamp ? new Date(d.timestamp).toISOString().split('T')[0] : new Date().toISOString().split('T')[0];

    if (d.displayUrl) images.push(d.displayUrl);
    if (d.childPosts) d.childPosts.forEach(c => { if (c.displayUrl) images.push(c.displayUrl); });
    if (d.sidecarImages) d.sidecarImages.forEach(i => { if (i.url) images.push(i.url); });

    prompt = text.replace(/https?:\/\/\S+/g, '').trim();
    sourceUrl = d.url || `https://instagram.com/p/${d.shortCode || id}/`;
  }
  else {
    debug.skipped_no_platform++;
    continue;
  }

  const prefix = { twitter: 'tw', threads: 'th', instagram: 'ig' }[platform];

  // Relaxed filter: prompt >= 20 chars, must have image, no likes minimum
  if (prompt && prompt.length >= 20 && images.length > 0) {
    results.push({
      id: `${prefix}_${id}`,
      prompt, author, author_name: authorName,
      likes, views, images,
      date, source_url: sourceUrl,
      platform
    });
    debug.accepted++;
  } else {
    debug.skipped_filter++;
  }
}

// Deduplicate
const seen = new Set();
const unique = results.filter(r => {
  if (seen.has(r.id)) return false;
  seen.add(r.id);
  return true;
});

if (unique.length === 0) {
  return [{ json: { _empty: true, message: 'No valid prompts found', debug } }];
}

return unique.map(r => ({ json: r }));

// Auto-detect model and categories
const items = $input.all();

function detectModel(prompt, sourceUrl) {
  const lower = (prompt + ' ' + (sourceUrl || '')).toLowerCase();
  if (/gpt.?image|4o.?image/i.test(lower)) return 'gptimage';
  if (/midjourney/i.test(lower)) return 'midjourney';
  if (/flux.*kontext/i.test(lower)) return 'flux';
  if (/nano.?banana.?2/i.test(lower)) return 'nanobanana2';
  if (/nano.?banana/i.test(lower)) return 'nanobanana';
  if (/imagen/i.test(lower)) return 'imagen';
  if (/grok/i.test(lower)) return 'grok';
  return 'nanobanana';
}

function categorize(prompt) {
  const lower = (prompt || '').toLowerCase();
  const cats = [];
  if (prompt && prompt.includes('{') && prompt.includes('}')) cats.push('JSON');

  const map = {
    'Photograph': ['photo', 'portrait', 'camera', 'lens', 'f/', 'cinematic', 'photorealistic'],
    'Girl': ['woman', 'girl', 'female', 'blonde', 'brunette'],
    'Boy': ['man', 'boy', 'male', 'beard'],
    'Product': ['product', 'bottle', 'packaging', 'brand', 'mockup'],
    'Food': ['food', 'dish', 'recipe', 'cuisine', 'ingredient'],
    '3D': ['3d', 'render', 'isometric', 'voxel'],
    'Anime': ['anime', 'manga', 'chibi'],
    'Logo': ['logo', 'branding', 'emblem'],
  };
  for (const [cat, kws] of Object.entries(map)) {
    if (kws.some(kw => lower.includes(kw))) cats.push(cat);
  }
  if (cats.length === 0) cats.push('Other');
  return cats;
}

const filtered = items.filter(i => !i.json._empty);
if (filtered.length === 0) {
  return [{ json: { _empty: true } }];
}

return filtered.map(item => {
  const d = item.json;
  return {
    json: {
      ...d,
      model: detectModel(d.prompt, d.source_url),
      categories: categorize(d.prompt),
      image: (d.images && d.images[0]) || '',
    }
  };
});

// Read existing prompts, merge new ones, save
const fs = require('fs');
const PROMPTS_PATH = '/opt/kgen-gallery/web-ui/data/trending-prompts.json';

const inputItems = $input.all().filter(i => !i.json._empty);
if (inputItems.length === 0) {
  return [{ json: { totalExisting: 0, newAdded: 0, totalAfter: 0, addedPrompts: [] } }];
}

// Load existing
let existing = [];
try {
  existing = JSON.parse(fs.readFileSync(PROMPTS_PATH, 'utf-8'));
} catch (e) {
  // File doesn't exist yet
}

const existingIds = new Set(existing.map(p => p.id));
const newItems = inputItems.map(i => i.json);
const added = [];

for (const item of newItems) {
  if (!existingIds.has(item.id)) {
    added.push({
      rank: 0,
      id: item.id,
      prompt: item.prompt,
      author: item.author,
      author_name: item.author_name,
      likes: item.likes,
      views: item.views,
      image: item.image,
      images: item.images,
      model: item.model,
      categories: item.categories,
      date: item.date,
      source_url: item.source_url,
    });
    existingIds.add(item.id);
  }
}

if (added.length > 0) {
  const merged = [...existing, ...added];
  merged.sort((a, b) => (b.likes || 0) - (a.likes || 0));
  merged.forEach((p, i) => p.rank = i + 1);
  fs.writeFileSync(PROMPTS_PATH, JSON.stringify(merged, null, 2), 'utf-8');
}

return [{
  json: {
    totalExisting: existing.length,
    newAdded: added.length,
    totalAfter: existing.length + added.length,
    addedPrompts: added.map(a => ({
      author: a.author,
      prompt: (a.prompt || '').substring(0, 80) + '...',
      likes: a.likes,
      model: a.model,
      platform: (a.source_url || '').includes('threads') ? 'threads' : (a.source_url || '').includes('instagram') ? 'instagram' : 'twitter',
      categories: a.categories,
    })),
  }
}];

const data = $input.first().json;

const platformEmoji = { twitter: '🐦', threads: '🧵', instagram: '📸' };

let message = `🎨 *KGen Gallery Update*\n\n`;
message += `✅ *${data.newAdded}* prompt mới đã thêm!\n`;
message += `📊 Tổng gallery: *${data.totalAfter}* prompts\n\n`;

if (data.addedPrompts && data.addedPrompts.length > 0) {
  message += `📝 *Chi tiết:*\n`;
  for (const p of data.addedPrompts.slice(0, 10)) {
    const emoji = platformEmoji[p.platform] || '📄';
    const cleanPrompt = (p.prompt || '').replace(/[_*\[\]()~`>#+=|{}.!-]/g, '');
    message += `${emoji} @${p.author} (${p.likes}❤️)\n`;
    message += `   Model: ${p.model} | ${(p.categories || []).join(', ')}\n`;
    message += `   _"${cleanPrompt}"_\n\n`;
  }
  if (data.addedPrompts.length > 10) {
    message += `...và ${data.addedPrompts.length - 10} prompt khác\n`;
  }
}

const now = new Date();
const vnTime = now.toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh' });
message += `\n⏰ ${vnTime}`;

return [{ json: { message, newAdded: data.newAdded } }];
